    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // public fetchTrades
        //
        //     {
        //         "amount":"0.0632",
        //         "price":"0.037288",
        //         "side":"BUY",
        //         "timestamp":1599279694576
        //     }
        //
        // private fetchOrderTrades
        //
        //      {
        //          "id": "608717046691139584",
        //          "orderId": "608716957545402368",
        //          "symbol": "BTC_BRL",
        //          "side": "BUY",
        //          "amount": "0.0988",
        //          "price": "45514.76",
        //          "fee": "0.0000988 BTC",
        //          "feeAmount": "0.0000988",
        //          "feeCurrency": "BTC",
        //          "role": "MAKER",
        //          "timestamp": 1565171053345
        //       }
        //
        // private fetchMyTrades (same endpoint as fetchOrderTrades)
        //
        //      {
        //          "id": "608717046691139584",
        //          "orderId": "608716957545402368",
        //          "symbol": "BTC_BRL",
        //          "side": "BUY",
        //          "amount": "0.0988",
        //          "price": "45514.76",
        //          "fee": "0.0000988 BTC",
        //          "feeAmount": "0.0000988",
        //          "feeCurrency": "BTC",
        //          "role": "MAKER",
        //          "timestamp": 1565171053345
        //       }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString(trade, "id");
        Object orderId = this.safeString(trade, "orderId");
        Object timestamp = this.safeInteger(trade, "timestamp");
        Object side = this.safeStringLower(trade, "side");
        Object priceString = this.safeString(trade, "price");
        Object amountString = this.safeString(trade, "amount");
        Object marketId = this.safeString(trade, "symbol");
        Object symbol = this.safeSymbol(marketId, market, "_");
        Object takerOrMaker = this.safeStringLower(trade, "role");
        Object feeString = this.safeString(trade, "fee");
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(feeString, null)))
        {
            Object feeCurrencyId = this.safeString(trade, "feeCurrency");
            Object feeCurrencyCode = this.safeCurrencyCode(feeCurrencyId);
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", NovadaxCore.this.safeString(trade, "feeAmount") );
                put( "currency", feeCurrencyCode );
            }};
        }
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "order", orderId );
            put( "timestamp", timestamp );
            put( "datetime", NovadaxCore.this.iso8601(timestamp) );
            put( "symbol", symbol );
            put( "type", null );
            put( "side", side );
            put( "price", priceString );
            put( "amount", amountString );
            put( "cost", null );
            put( "takerOrMaker", takerOrMaker );
            put( "fee", finalFee );
            put( "info", trade );
        }}, market);
    }

