    /**
     * @method
     * @name novadax#createOrder
     * @description create a trade order
     * @see https://doc.novadax.com/en-US/#order-introduction
     * @param {string} symbol unified symbol of the market to create an order in
     * @param {string} type 'market' or 'limit'
     * @param {string} side 'buy' or 'sell'
     * @param {float} amount how much you want to trade in units of the base currency
     * @param {float} [price] the price at which the order is to be fulfilled, in units of the quote currency, ignored in market orders
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {float} [params.cost] for spot market buy orders, the quote quantity that can be used as an alternative for the amount
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createOrder(Object symbol, Object type, Object side, Object amount, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object price = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object uppercaseType = ((String)type).toUpperCase();
            Object uppercaseSide = ((String)side).toUpperCase();
            final Object finalUppercaseSide = uppercaseSide;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
                put( "side", finalUppercaseSide );
            }};
            Object triggerPrice = this.safeValue2(parameters, "triggerPrice", "stopPrice");
            if (Helpers.isTrue(Helpers.isEqual(triggerPrice, null)))
            {
                if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(uppercaseType, "STOP_LIMIT"))) || Helpers.isTrue((Helpers.isEqual(uppercaseType, "STOP_MARKET")))))
                {
                    throw new ArgumentsRequired((String)Helpers.add(Helpers.add(Helpers.add(this.id, " createOrder() requires a stopPrice parameter for "), uppercaseType), " orders")) ;
                }
            } else
            {
                if (Helpers.isTrue(Helpers.isEqual(uppercaseType, "LIMIT")))
                {
                    uppercaseType = "STOP_LIMIT";
                } else if (Helpers.isTrue(Helpers.isEqual(uppercaseType, "MARKET")))
                {
                    uppercaseType = "STOP_MARKET";
                }
                Object defaultOperator = ((Helpers.isTrue((Helpers.isEqual(uppercaseSide, "BUY"))))) ? "LTE" : "GTE";
                Helpers.addElementToObject(request, "operator", this.safeString(parameters, "operator", defaultOperator));
                Helpers.addElementToObject(request, "stopPrice", this.priceToPrecision(symbol, triggerPrice));
                parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("triggerPrice", "stopPrice")));
            }
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(uppercaseType, "LIMIT"))) || Helpers.isTrue((Helpers.isEqual(uppercaseType, "STOP_LIMIT")))))
            {
                Helpers.addElementToObject(request, "price", this.priceToPrecision(symbol, price));
                Helpers.addElementToObject(request, "amount", this.amountToPrecision(symbol, amount));
            } else if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(uppercaseType, "MARKET"))) || Helpers.isTrue((Helpers.isEqual(uppercaseType, "STOP_MARKET")))))
            {
                if (Helpers.isTrue(Helpers.isEqual(uppercaseSide, "SELL")))
                {
                    Helpers.addElementToObject(request, "amount", this.amountToPrecision(symbol, amount));
                } else if (Helpers.isTrue(Helpers.isEqual(uppercaseSide, "BUY")))
                {
                    Object quoteAmount = null;
                    Object createMarketBuyOrderRequiresPrice = true;
                    var createMarketBuyOrderRequiresPriceparametersVariable = this.handleOptionAndParams(parameters, "createOrder", "createMarketBuyOrderRequiresPrice", true);
                    createMarketBuyOrderRequiresPrice = ((java.util.List<Object>) createMarketBuyOrderRequiresPriceparametersVariable).get(0);
                    parameters = ((java.util.List<Object>) createMarketBuyOrderRequiresPriceparametersVariable).get(1);
                    Object cost = this.safeNumber2(parameters, "cost", "value");
                    parameters = this.omit(parameters, "cost");
                    if (Helpers.isTrue(!Helpers.isEqual(cost, null)))
                    {
                        quoteAmount = this.costToPrecision(symbol, cost);
                    } else if (Helpers.isTrue(createMarketBuyOrderRequiresPrice))
                    {
                        if (Helpers.isTrue(Helpers.isEqual(price, null)))
                        {
                            throw new InvalidOrder((String)Helpers.add(this.id, " createOrder() requires the price argument for market buy orders to calculate the total cost to spend (amount * price), alternatively set the createMarketBuyOrderRequiresPrice option or param to false and pass the cost to spend (quote quantity) in the amount argument")) ;
                        } else
                        {
                            Object amountString = this.numberToString(amount);
                            Object priceString = this.numberToString(price);
                            Object costRequest = Precise.stringMul(amountString, priceString);
                            quoteAmount = this.costToPrecision(symbol, costRequest);
                        }
                    } else
                    {
                        quoteAmount = this.costToPrecision(symbol, amount);
                    }
                    Helpers.addElementToObject(request, "value", quoteAmount);
                }
            }
            Helpers.addElementToObject(request, "type", uppercaseType);
            Object response = (this.privatePostOrdersCreate(this.extend(request, parameters))).join();
            //
            //     {
            //         "code": "A10000",
            //         "data": {
            //             "amount": "0.001",
            //             "averagePrice": null,
            //             "filledAmount": "0",
            //             "filledFee": "0",
            //             "filledValue": "0",
            //             "id": "870613508008464384",
            //             "operator": "GTE",
            //             "price": "210000",
            //             "side": "BUY",
            //             "status": "SUBMITTED",
            //             "stopPrice": "211000",
            //             "symbol": "BTC_BRL",
            //             "timestamp": 1627612035528,
            //             "type": "STOP_LIMIT",
            //             "value": "210"
            //         },
            //         "message": "Success"
            //     }
            //
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            return this.parseOrder(data, market);
        });

    }

